// pubspec: flutter_riverpod: ^2.5.0

// ── Simple providers ──────────────────────────────
final apiUrlProvider = Provider<String>((ref) => 'https://api.example.com');
final counterProvider = StateProvider<int>((ref) => 0);

// ── AsyncNotifier — recommended for async state ────
class ProductsNotifier extends AsyncNotifier<List<Product>> {
  @override
  Future<List<Product>> build() async {
    // Called once on first use; result is cached
    final repo = ref.watch(productRepositoryProvider);
    return repo.getProducts();
  }

  Future<void> refresh() async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(() =>
      ref.read(productRepositoryProvider).getProducts()
    );
  }

  Future<void> addProduct(Product p) async {
    final repo = ref.read(productRepositoryProvider);
    await repo.create(p);
    ref.invalidateSelf(); // re-run build()
  }
}

final productsProvider = AsyncNotifierProvider<ProductsNotifier, List<Product>>(
  ProductsNotifier.new,
);

// ── Combining providers ────────────────────────────
final searchProvider = StateProvider<String>((ref) => '');

final filteredProductsProvider = Provider<AsyncValue<List<Product>>>((ref) {
  final products = ref.watch(productsProvider);
  final search   = ref.watch(searchProvider);
  return products.whenData((list) =>
    list.where((p) => p.name.toLowerCase().contains(search.toLowerCase())).toList(),
  );
});

// ── Widget usage ────────────────────────────────────
class ProductsPage extends ConsumerWidget {
  const ProductsPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final products = ref.watch(filteredProductsProvider);

    return products.when(
      data: (list) => ListView.builder(
        itemCount: list.length,
        itemBuilder: (ctx, i) => ProductTile(product: list[i]),
      ),
      loading: () => const CircularProgressIndicator(),
      error: (e, _) => Text('Error: $e'),
    );
  }
}

// ── ConsumerStatefulWidget ─────────────────────────
class SearchPage extends ConsumerStatefulWidget {
  @override ConsumerState<SearchPage> createState() => _SearchPageState();
}
class _SearchPageState extends ConsumerState<SearchPage> {
  @override Widget build(BuildContext context) {
    return TextField(
      onChanged: (v) => ref.read(searchProvider.notifier).state = v,
    );
  }
}

// ── family modifier ────────────────────────────────
// Provider parameterized by product ID
final productProvider = FutureProvider.family<Product, int>((ref, id) async {
  final repo = ref.watch(productRepositoryProvider);
  return repo.getProduct(id);
});

// Usage in widget — each ID gets its own cached provider
class ProductPage extends ConsumerWidget {
  final int productId;
  const ProductPage({super.key, required this.productId});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final product = ref.watch(productProvider(productId)); // unique per ID
    return product.when(
      data: (p) => Text(p.name),
      loading: () => const CircularProgressIndicator(),
      error: (e, _) => Text('Error: $e'),
    );
  }
}

// ── Combining family with autoDispose ────────────────
final userPostsProvider = StreamProvider.autoDispose.family<List<Post>, int>(
  (ref, userId) {
    final repo = ref.watch(postRepositoryProvider);
    return repo.watchPosts(userId); // auto-cancels stream when widget leaves
  },
);

// ── Overriding in tests ─────────────────────────────
class FakeProductRepository implements ProductRepository {
  @override Future<Product> getProduct(int id) async =>
      Product(id: id, name: 'Fake Product', price: 9.99);
  @override Future<List<Product>> getProducts({int page = 1}) async => [];
}

void main() {
  testWidgets('ProductPage shows product name', (tester) async {
    await tester.pumpWidget(
      ProviderScope(
        overrides: [
          // Override the repository — affects all providers that depend on it
          productRepositoryProvider.overrideWithValue(FakeProductRepository()),
        ],
        child: MaterialApp(
          home: ProductPage(productId: 42),
        ),
      ),
    );
    await tester.pumpAndSettle();
    expect(find.text('Fake Product'), findsOneWidget);
  });

  // Unit testing a notifier
  test('ProductsNotifier loads products', () async {
    final container = ProviderContainer(
      overrides: [
        productRepositoryProvider.overrideWithValue(FakeProductRepository()),
      ],
    );
    addTearDown(container.dispose);

    final notifier = container.read(productsProvider.notifier);
    await container.read(productsProvider.future);

    expect(container.read(productsProvider).hasValue, true);
  });
}

final counterProvider = StateProvider<int>((ref) => 0);
final authProvider = AsyncNotifierProvider<AuthNotifier, User?>(AuthNotifier.new);

class HomePage extends ConsumerWidget {
  const HomePage({super.key});
  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // ✅ watch — rebuilds the Text when count changes
    final count = ref.watch(counterProvider);

    // ✅ listen — pushes the user to /login when auth flips to null,
    //   without forcing this widget to rebuild on every auth change
    ref.listen<AsyncValue<User?>>(authProvider, (prev, next) {
      if (prev?.value != null && next.value == null) {
        Navigator.of(context).pushNamedAndRemoveUntil('/login', (_) => false);
      }
      next.whenOrNull(error: (e, _) =>
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(content: Text('$e'))),
      );
    });

    return Column(children: [
      Text('count = $count'),
      ElevatedButton(
        // ✅ read — this callback should not subscribe to counter
        onPressed: () => ref.read(counterProvider.notifier).state++,
        child: const Text('+'),
      ),
    ]);
  }
}

// ❌ Anti-pattern — read in build() drops updates
// final count = ref.read(counterProvider);  // never refreshes

// ❌ Anti-pattern — watch in a callback rebuilds the parent on every tap
// onPressed: () { final c = ref.watch(counterProvider); ... }

// Screen-scoped — cached only while the screen is alive
final searchResultsProvider = AutoDisposeFutureProvider.family<List<Hit>, String>(
  (ref, query) async {
    // ✅ Disposed when the search screen pops
    return ref.watch(apiProvider).search(query);
  },
);

// Keep recent results around for a few minutes after the user navigates away,
// so back-navigation reuses the cache instead of re-fetching
final cachedSearchProvider = AutoDisposeProvider.family<Stream<List<Hit>>, String>(
  (ref, query) {
    final link = ref.keepAlive();                    // ✅ stays alive on dispose
    final timer = Timer(const Duration(minutes: 5), link.close);
    ref.onDispose(timer.cancel);                     // free the timer if container shuts down
    return ref.watch(apiProvider).searchStream(query);
  },
);

// Long-running upload — never dispose mid-flight
class UploadNotifier extends AutoDisposeAsyncNotifier<UploadState> {
  @override
  Future<UploadState> build() async {
    final link = ref.keepAlive();
    ref.onDispose(() {
      // Will only run after we close the link below
      _cancellationToken.cancel();
    });
    final result = await api.upload(file, token: _cancellationToken);
    link.close();   // ✅ done — let the provider be disposed normally
    return result;
  }
}

