import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

part 'app.g.dart';

// 1) Plain provider
@riverpod
String apiBaseUrl(ApiBaseUrlRef ref) => const String.fromEnvironment('API_URL');
// → final apiBaseUrlProvider = Provider.autoDispose<String>((ref) => ...);

// 2) Family inferred from positional arg
@riverpod
Future<Product> product(ProductRef ref, int id) async {
  final api = ref.watch(apiClientProvider);
  return api.fetchProduct(id);
}
// → ref.watch(productProvider(42))

// 3) Notifier from a class
@riverpod
class Cart extends _\$Cart {
  @override
  List<Item> build() => [];

  void add(Item item) => state = [...state, item];
  void clear()       => state = [];
  int get total      => state.fold(0, (a, b) => a + b.price);
}
// → final cartProvider = NotifierProvider.autoDispose<Cart, List<Item>>(...)

// 4) AsyncNotifier — return type Future<T> drives the choice
@riverpod
class Profile extends _\$Profile {
  @override
  Future<User> build() async => ref.watch(apiClientProvider).me();

  Future<void> refresh() async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(
      () => ref.read(apiClientProvider).me(),
    );
  }
}

// 5) Keep-alive opt-in
@Riverpod(keepAlive: true)
ApiClient apiClient(ApiClientRef ref) => ApiClient(baseUrl: ref.watch(apiBaseUrlProvider));

// ── StateProvider — primitive value, no logic ──
final queryProvider = StateProvider<String>((ref) => '');
// Caller: ref.read(queryProvider.notifier).state = q;

// ── Notifier — synchronous logic, no IO ──
class FilterSet extends Notifier<Set<String>> {
  @override Set<String> build() => {};
  void toggle(String tag) => state = {...state}..(
    state.contains(tag) ? state.remove(tag) : state.add(tag));
  void clear() => state = {};
}
final filterProvider = NotifierProvider<FilterSet, Set<String>>(FilterSet.new);

// ── AsyncNotifier — IO + actions ──
class Profile extends AsyncNotifier<User> {
  @override
  Future<User> build() => ref.watch(apiProvider).me();

  Future<void> updateName(String name) async {
    state = const AsyncLoading();        // optimistic loading
    state = await AsyncValue.guard(() async {
      await ref.read(apiProvider).rename(name);
      return ref.read(apiProvider).me();
    });
  }
}
final profileProvider = AsyncNotifierProvider<Profile, User>(Profile.new);

// Consumer renders the three states without if-soup
class ProfileTile extends ConsumerWidget {
  const ProfileTile({super.key});
  @override
  Widget build(BuildContext context, WidgetRef ref) {
    return ref.watch(profileProvider).when(
      data: (u) => Text(u.name),
      loading: () => const Text('…'),
      error: (e, _) => Text('!$e'),
    );
  }
}

@freezed
class UiState with _\$UiState {
  const factory UiState({
    required ThemeMode theme,
    required Locale locale,
    required bool sidebarOpen,
    required int unreadCount,
  }) = _UiState;
}

final uiProvider = NotifierProvider<UiNotifier, UiState>(UiNotifier.new);

// ❌ Watches the whole state — rebuilds on every unread badge tick
class ThemeBadgeBad extends ConsumerWidget {
  const ThemeBadgeBad({super.key});
  @override Widget build(BuildContext c, WidgetRef ref) {
    final ui = ref.watch(uiProvider);
    return Icon(ui.theme == ThemeMode.dark ? Icons.dark_mode : Icons.light_mode);
  }
}

// ✅ Selects only the theme — never rebuilds for unread / sidebar / locale changes
class ThemeBadge extends ConsumerWidget {
  const ThemeBadge({super.key});
  @override Widget build(BuildContext c, WidgetRef ref) {
    final mode = ref.watch(uiProvider.select((s) => s.theme));
    return Icon(mode == ThemeMode.dark ? Icons.dark_mode : Icons.light_mode);
  }
}

// Selecting on AsyncValue
final nameProvider = Provider<String>((ref) =>
  ref.watch(profileProvider.select((s) => s.valueOrNull?.name ?? '...')));

// Splitting coarse state — each widget watches the focused provider
final themeProvider  = Provider<ThemeMode>((ref) => ref.watch(uiProvider.select((s) => s.theme)));
final unreadProvider = Provider<int>      ((ref) => ref.watch(uiProvider.select((s) => s.unreadCount)));

// 1) Root override — flavor-aware base URL
void main() {
  runApp(ProviderScope(
    overrides: [
      apiBaseUrlProvider.overrideWithValue(
        const String.fromEnvironment('API_URL', defaultValue: 'https://staging.example.com'),
      ),
    ],
    child: const App(),
  ));
}

// 2) Test override — replace the repository with a fake
testWidgets('shows fake product', (tester) async {
  await tester.pumpWidget(ProviderScope(
    overrides: [
      productRepositoryProvider.overrideWithValue(FakeProductRepo()),
