// 3) Sub-tree override — give the demo screen its own fake state
class DemoScreen extends StatelessWidget {
  const DemoScreen({super.key});
  @override
  Widget build(BuildContext context) {
    return ProviderScope(
      overrides: [
        // Children of this scope see a fixed cart with sample items
        cartProvider.overrideWith(() => Cart()..addAll(_sampleItems)),
      ],
      child: const CartScreen(),
    );
  }
}

// 4) Reset at runtime — remount the scope under a different key
ProviderScope(
  key: ValueKey(currentTenantId),     // key change → fresh container
  overrides: [
    tenantIdProvider.overrideWithValue(currentTenantId),
  ],
  child: const TenantApp(),
