// State exposes a transient action — widget reacts via ref.listen
class AuthNotifier extends AsyncNotifier<User?> {
  @override Future<User?> build() async => null;

  Future<void> signIn(String email, String pwd) async {
    state = const AsyncLoading();
    state = await AsyncValue.guard(() => api.signIn(email, pwd));
  }

  Future<void> signOut() async {
    await api.signOut();
    state = const AsyncData(null);
  }
}
final authProvider = AsyncNotifierProvider<AuthNotifier, User?>(AuthNotifier.new);

class App extends ConsumerWidget {
  const App({super.key});
  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // ✅ One global listener, not duplicated in every screen
    ref.listen<AsyncValue<User?>>(authProvider, (prev, next) {
      next.whenOrNull(
        data: (user) {
          if (prev?.value == null && user != null) {
            navigatorKey.currentState?.pushReplacementNamed('/home');
          }
          if (prev?.value != null && user == null) {
            navigatorKey.currentState?.pushNamedAndRemoveUntil('/login', (_) => false);
          }
        },
        error: (e, _) {
          ScaffoldMessenger.of(navigatorKey.currentContext!)
              .showSnackBar(SnackBar(content: Text('$e')));
        },
      );
    });

    return MaterialApp(
      navigatorKey: navigatorKey,
      home: const SplashGate(),
    );
  }
}

